1	type Item = { type: string };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	
6	const PREMIUM_FOR_SINGLE_ITEM: Record<string, number> = {
7	  amulet: 71,
8	  staff: 93,
9	  potion: 49,
10	  sword: 115,
11	  rune: 33,
12	};
13	
14	const PREMIUM_FOR_TWO_RUNES = 60;
15	const PREMIUM_FOR_THREE_RUNES = 71;
16	const PREMIUM_FOR_FOUR_RUNES = 115;
17	
18	export function runScenario(input: unknown): unknown {
19	  const { steps } = input as Scenario;
20	  const premium = computePremium(steps[0].items);
21	  return { results: [{ premium }] };
22	}
23	
24	function computePremium(items: Item[]): number {
25	  if (items.length === 0) return PROCESSING_FEE;
26	  if (items.length === 4 && items.every(isRune)) return PREMIUM_FOR_FOUR_RUNES;
27	  if (items.length === 3 && items.every(isRune)) return PREMIUM_FOR_THREE_RUNES;
28	  if (items.length === 2 && items[0].type === "rune") return PREMIUM_FOR_TWO_RUNES;
29	  return PREMIUM_FOR_SINGLE_ITEM[items[0].type];
30	}
31	
32	function isRune(item: Item): boolean {
33	  return item.type === "rune";
34	}
